def decode(s: str) -> str:
    # Use a stack to handle nesting.
    # Each element in the stack is either a string (literal text accumulated so far)
    # or we can structure it as: stack of lists, where we append characters/strings to the current list.
    # However, a simpler recursive descent or stack-based approach for nested brackets is often easier.

    # Let's use a recursive approach with an index pointer to handle the nesting naturally.

    index = 0
    n = len(s)

    def parse():
        nonlocal index
        result = []

        while index < n and s[index] != ']':
            if s[index].isdigit():
                # Parse the full number
                start = index
                while index < n and s[index].isdigit():
                    index += 1
                k = int(s[start:index])

                # Expect '['
                if index < n and s[index] == '[':
                    index += 1  # skip '['
                    # Recursively parse the content inside the brackets
                    substring = parse()
                    # Expect ']'
                    if index < n and s[index] == ']':
                        index += 1  # skip ']'
                    else:
                        raise ValueError("Unbalanced brackets")
                    result.append(substring * k)
                else:
                    raise ValueError("Expected '[' after number")
            else:
                # Literal character
                result.append(s[index])
                index += 1

        return "".join(result)

    return parse()

