    stack = [1, '']
    num = 0
    for c in s:
        if c.isdigit():
            num = num * 10 + int(c)
        elif c == '[':
            stack.append(num)
            stack.append('')
            num = 0
        elif c == ']':
            count, prev = stack.pop(), stack.pop()
            stack[-1] += prev * count
        else:
            stack[-1] += c
    return stack[-1]

